public void ETGParentProdId_jumpref(FormStringControl _control)
{
    ProdTable prodTable;
    prodTable prodTableCurr = this.dataSource(1).cursor();
    DataAreaId targetCompany;

    select firstOnly crossCompany prodTable
            where prodTable.ProdId == prodTableCurr.ETGParentProdId;

    if (prodTable)
    {
        targetCompany = prodTable.DataAreaId;

        changeCompany(targetCompany)
        {
            Args args = new Args();
            args.record(prodTable);
            new MenuFunction(menuItemDisplayStr(ProdTable), MenuItemType::Display).run(args);
        }
    }
}

