public void init()
{
    FormStringControl formStringControl;
    FormStringControl formStringControlsub;
    next init();

    formStringControl = this.design().controlName(formControlStr(ProdTable, ProdTable_ETGParentprodId));
    formStringControl.registerOverrideMethod(methodStr(FormStringControl, jumpRef),methodStr(ETGProdTableForm_Extension,ETGParentProdId_jumpref));

    formStringControlsub = this.design().controlName(formControlStr(ProdTable, ProdTable_ETGChildprodId));
    formStringControlsub.registerOverrideMethod(methodStr(FormStringControl, jumpRef),methodStr(ETGProdTableForm_Extension,ETGChildProdId_jumpref));
}
